/* selectMdb01List */
SELECT CONCAT(A.COMPKEY, A.WAREKEY, A.BVLCODE) as ROWKEY
	 , A.COMPKEY, A.WAREKEY, A.BVLCODE
     , IF((SELECT COUNT(*) FROM BLGTIT WHERE COMPKEY=A.COMPKEY AND WAREKEY=A.WAREKEY AND BVLCODE=A.BVLCODE)>0,'Y','N') AS BILGCNT
	 , A.OWNERKY, A.PTNRKEY, A.BLRPMGB
	 , A.BLRCSGB, A.BLRTKGB, A.BLRUNIT
	 , A.DOCCATE, A.DOCTYPE, A.BLRCOST, A.BLRSUTX
	 , CONCAT(SUBSTR(A.BLRDATE, 1, 4),'-',SUBSTR(A.BLRDATE, 5, 2)) as BLRDATE, A.BLRDTGB, A.BLRMFGB, A.BLRCFDT
	 , A.BLRMTGB, A.BLRCTDT, A.BLRTKNM, A.BLUSEYN
	 , fn_com_todate(A.CREDATE) as CREDATE , fn_com_totime(A.CRETIME) as CRETIME , fn_sy_usernam(A.COMPKEY, A.CREUSER) as CREUSER
	 , fn_com_todate(A.LMODATE) as LMODATE , fn_com_totime(A.LMOTIME) as LMOTIME , fn_sy_usernam(A.COMPKEY, A.LMOUSER) as LMOUSER
	 , UPDTCHK, INDIBZL, INDIARC
  FROM BVLRMA A

/* 해당 월 적용될 단가 마스터 위주 */
 INNER JOIN (
			SELECT COMPKEY, WAREKEY, OWNERKY, PTNRKEY, BLRPMGB, BLRCSGB, BLRTKGB, BLRUNIT, DOCCATE, DOCTYPE, MAX(BLRDATE) AS BLRDATE
			  FROM BVLRMA
			 WHERE COMPKEY = #{userData.compkey}
			   AND WAREKEY = #{warekey}
	  AND BLRDATE <= #{blrdate} 
			   AND BLUSEYN = 'Y'
			 GROUP BY COMPKEY, WAREKEY, OWNERKY, PTNRKEY, BLRPMGB, BLRCSGB, BLRTKGB, BLRUNIT, DOCCATE, DOCTYPE
     ) C
    ON A.COMPKEY = C.COMPKEY
   AND A.WAREKEY = C.WAREKEY
   AND A.OWNERKY = C.OWNERKY
   AND A.PTNRKEY = C.PTNRKEY
   AND A.BLRPMGB = C.BLRPMGB
   AND A.BLRCSGB = C.BLRCSGB
   AND A.BLRTKGB = C.BLRTKGB
   AND A.BLRUNIT = C.BLRUNIT
   AND A.DOCCATE = C.DOCCATE
   AND A.DOCTYPE = C.DOCTYPE
   AND A.BLRDATE = C.BLRDATE

 WHERE 1=1
   AND A.COMPKEY= #{userData.compkey}
   AND A.WAREKEY = #{warekey}

	AND A.OWNERKY = #{ownerky}


	AND A.PTNRKEY = #{ptnrkey}


	AND A.BLRPMGB = #{blrpmgb}


	AND A.BLRCSGB = #{blrcsgb}


	AND A.BLRTKGB = #{blrtkgb}


	AND A.BLRUNIT = #{blrunit}

ORDER BY

	A.COMPKEY, A.WAREKEY, A.OWNERKY, A.PTNRKEY, A.BLRPMGB


	A.BLRDATE, A.BVLCODE

