/* selectMdb04List */
SELECT CONCAT(A.COMPKEY, A.WAREKEY, A.BVTCODE) as ROWKEY
	 , A.COMPKEY, A.WAREKEY, A.BVTCODE
	 , IF((SELECT COUNT(*) FROM BTGTIT WHERE COMPKEY=A.COMPKEY AND WAREKEY=A.WAREKEY AND BVTCODE=A.BVTCODE)>0,'Y','N') AS BILGCNT
	 , A.PTNRKEY, A.BTRPMGB, A.BTRCSGB, A.BTRTKGB, A.VEHICKY, A.BTRUNIT
	 , A.DOCCATE, A.DOCTYPE, A.SHTRTKY, A.BTRCOST, A.BTRSUTX
	 , CONCAT(SUBSTR(A.BTRDATE, 1, 4),'-',SUBSTR(A.BTRDATE, 5, 2)) as BTRDATE, A.BTRDTGB, A.BTRMFGB, A.BTRCFDT
	 , A.BTRMTGB, A.BTRCTDT, A.BTRTKNM, A.BTUSEYN
	 , fn_com_todate(A.CREDATE) as CREDATE , fn_com_totime(A.CRETIME) as CRETIME , fn_sy_usernam(A.COMPKEY, A.CREUSER) as CREUSER
	 , fn_com_todate(A.LMODATE) as LMODATE , fn_com_totime(A.LMOTIME) as LMOTIME , fn_sy_usernam(A.COMPKEY, A.LMOUSER) as LMOUSER
	 , A.UPDTCHK, A.INDIBZL, A.INDIARC
  FROM BVTRMA A

	/* 해당 월 적용될 단가 마스터 위주 */
 INNER JOIN (
			SELECT COMPKEY, WAREKEY, PTNRKEY, BTRPMGB, BTRCSGB, BTRTKGB, SHTRTKY, VEHICKY, BTRUNIT, DOCCATE, DOCTYPE, MAX(BTRDATE) AS BTRDATE
			  FROM BVTRMA
			 WHERE COMPKEY = #{userData.compkey}
			   AND WAREKEY = #{warekey}
	  AND BTRDATE <= #{btrdate} 
			   AND BTUSEYN = 'Y'
			 GROUP BY COMPKEY, WAREKEY, PTNRKEY, BTRPMGB, BTRCSGB, BTRTKGB, SHTRTKY, VEHICKY, BTRUNIT, DOCCATE, DOCTYPE
	 ) C
	ON A.COMPKEY = C.COMPKEY
	AND A.WAREKEY = C.WAREKEY
	AND A.PTNRKEY = C.PTNRKEY
	AND A.BTRPMGB = C.BTRPMGB
	AND A.BTRCSGB = C.BTRCSGB
	AND A.BTRTKGB = C.BTRTKGB
	AND IFNULL(A.SHTRTKY, '') = IFNULL(C.SHTRTKY, '')
	AND A.VEHICKY = C.VEHICKY
	AND A.BTRUNIT = C.BTRUNIT
	AND A.DOCCATE = C.DOCCATE
	AND A.DOCTYPE = C.DOCTYPE
	AND A.BTRDATE = C.BTRDATE

 WHERE A.COMPKEY= #{userData.compkey}
   AND A.WAREKEY = #{warekey}

	AND A.VEHICKY = #{vehicky}


	AND A.BTRPMGB = #{btrpmgb}


	AND A.PTNRKEY = #{ptnrkey}


	AND A.BTRCSGB = #{btrcsgb}


	AND A.BTRTKGB = #{btrtkgb}


	AND A.BTRUNIT = #{btrunit}

ORDER BY

	A.COMPKEY, A.WAREKEY, A.PTNRKEY, A.BTRPMGB


	A.BTRDATE, A.BVTCODE

